// DOM event listener overloads expose currentTarget as EventTarget. Portal form
// handlers are registered directly on forms, so keep that relationship explicit.
class FormData extends globalThis.FormData {
  constructor(form?: EventTarget | null) { super(form as HTMLFormElement | undefined); }
}
declare global {
  interface EventTarget { querySelector<E extends Element = Element>(selectors: string): E | null; }
}

type Row = Record<string, any>;
const app = document.querySelector<HTMLElement>("#app")!;
const icon: Record<string, string> = {
  overview: "⌂", ideas: "◇", filming: "◉", calendar: "□", content: "▤", performance: "↗",
  files: "⌑", account: "○", clients: "◎", admin: "◫", requests: "!", analytics: "⌁", users: "+",
};
const clientNav = [
  ["overview", "Overview"], ["ideas", "Ideas"], ["filming", "Filming"], ["calendar", "Calendar"],
  ["content", "Content"], ["performance", "Performance"], ["files", "Files"], ["account", "Account"],
];
const adminNav = [["clients", "All clients"], ["admin", "Admin dashboard"], ["requests", "Requests"], ["analytics", "Analytics management"], ["users", "User management"]];

function busy(button: HTMLButtonElement | null, value: boolean, text = "Working…"): void {
  if (!button) return;
  if (value) { button.dataset.label = button.textContent || ""; button.textContent = text; button.disabled = true; }
  else { button.textContent = button.dataset.label || button.textContent; button.disabled = false; }
}

let dialogReturnFocus: HTMLElement | null = null;
function closeDialog(): void {
  document.querySelector(".dialog-backdrop")?.remove();
  dialogReturnFocus?.focus();
  dialogReturnFocus = null;
}
function dialog(title: string, eyebrow: string, body: string, wide = false): HTMLElement {
  const existing = document.querySelector(".dialog-backdrop");
  if (!existing) dialogReturnFocus = document.activeElement instanceof HTMLElement ? document.activeElement : null;
  else existing.remove();
  const backdrop = document.createElement("div");
  backdrop.className = "dialog-backdrop";
  backdrop.innerHTML = `<section class="dialog ${wide ? "wide" : ""}" role="dialog" aria-modal="true" aria-labelledby="dialog-title">
    <header class="dialog-head"><div><span class="eyebrow">${e(eyebrow)}</span><h2 id="dialog-title">${e(title)}</h2></div><button class="icon-button" data-close-dialog aria-label="Close">×</button></header>${body}</section>`;
  backdrop.addEventListener("click", event => { if (event.target === backdrop || (event.target as Element).closest("[data-close-dialog]")) closeDialog(); });
  document.body.append(backdrop);
  const focusable = () => [...backdrop.querySelectorAll<HTMLElement>('button:not([disabled]),a[href],input:not([disabled]),textarea:not([disabled]),select:not([disabled]),[tabindex]:not([tabindex="-1"])')];
  focusable()[0]?.focus();
  backdrop.addEventListener("keydown", event => {
    if (event.key !== "Tab") return;
    const elements = focusable();
    if (!elements.length) return;
    const first = elements[0], last = elements[elements.length - 1];
    if (event.shiftKey && document.activeElement === first) { event.preventDefault(); last.focus(); }
    else if (!event.shiftKey && document.activeElement === last) { event.preventDefault(); first.focus(); }
  });
  return backdrop;
}

function setupScreen(): void {
  app.innerHTML = `<main class="auth-page" id="workspace-main"><section class="auth-brand"><img class="auth-logo" src="/brand/mase-logo.png" alt="Mase the Creative"><div><h1>Your content work,<br><em>all in one place.</em></h1><p>Mase Workspace brings ideas, filming plans, approvals, files and performance together around each client.</p></div><div class="auth-mark">Private client workspace</div></section><section class="auth-panel"><div class="auth-card"><span class="eyebrow">Configuration required</span><h2>Connect Supabase</h2><p>The portal is installed securely, but it needs its Supabase project URL and public anonymous key before anyone can sign in.</p><div class="message">Add <strong>SUPABASE_URL</strong> and <strong>SUPABASE_ANON_KEY</strong> to the environment, apply the included migration, then rebuild the site. The service-role key is used only by the server.</div><p class="auth-help">No credentials or example login have been embedded in the website.</p><a class="button ghost" href="/">Return to the website</a></div></section></main>`;
}

function loginScreen(mode: "login" | "reset" | "update" = "login", message = ""): void {
  const title = mode === "login" ? "Welcome back" : mode === "reset" ? "Reset your password" : "Choose a new password";
  const description = mode === "login" ? "Sign in to review ideas, approve content and keep your next shoot moving." : mode === "reset" ? "Enter the email address attached to your workspace." : "Use at least eight characters for your new password.";
  app.innerHTML = `<main class="auth-page" id="workspace-main"><section class="auth-brand"><img class="auth-logo" src="/brand/mase-logo.png" alt="Mase the Creative"><div><h1>Clearer content.<br><em>Smoother progress.</em></h1><p>One private place for the ideas, decisions and details behind the work Mase creates with you.</p></div><div class="auth-mark">Mase Workspace</div></section><section class="auth-panel"><div class="auth-card"><span class="eyebrow">Mase Workspace</span><h2>${title}</h2><p>${description}</p>${message ? `<div class="message">${e(message)}</div>` : ""}
    <form class="form" id="auth-form">
      ${mode !== "update" ? `<label class="field">Email address<input type="email" name="email" autocomplete="email" required placeholder="you@business.co.uk"></label>` : ""}
      ${mode !== "reset" ? `<label class="field">Password<input type="password" name="password" autocomplete="${mode === "login" ? "current-password" : "new-password"}" minlength="8" required></label>` : ""}
      <button class="button primary" type="submit">${mode === "login" ? "Sign in" : mode === "reset" ? "Send reset link" : "Update password"}</button>
    </form>
    <div class="form-actions">${mode === "login" ? `<button class="text-button" data-auth-mode="reset">Forgot your password?</button>` : `<button class="text-button" data-auth-mode="login">Back to sign in</button>`}</div>
    <p class="auth-help">Access is invitation-only. If you need an account, contact Mase the Creative.</p><a class="button ghost" href="/">Return to the website</a></div></section></main>`;
  app.querySelectorAll<HTMLElement>("[data-auth-mode]").forEach(button => button.addEventListener("click", () => loginScreen(button.dataset.authMode as "login" | "reset")));
  app.querySelector<HTMLFormElement>("#auth-form")?.addEventListener("submit", async event => {
    event.preventDefault();
    const formElement = event.currentTarget as HTMLFormElement;
    const form = new FormData(formElement);
    const button = formElement.querySelector<HTMLButtonElement>("button[type=submit]");
    busy(button, true);
    try {
      const client = requiredClient();
      if (mode === "login") {
        const { error } = await client.auth.signInWithPassword({ email: formValue(form, "email"), password: formValue(form, "password") });
        if (error) throw error;
      } else if (mode === "reset") {
        const { error } = await client.auth.resetPasswordForEmail(formValue(form, "email"), { redirectTo: `${location.origin}/portal/account/` });
        if (error) throw error;
        loginScreen("login", "Check your inbox for a secure password reset link.");
      } else {
        const { error } = await client.auth.updateUser({ password: formValue(form, "password") });
        if (error) throw error;
        toast("Your password has been updated.");
        go("account/");
      }
    } catch (error) { toast(error instanceof Error ? error.message : "Unable to continue.", "error"); }
    finally { busy(button, false); }
  });
}

async function loadWorkspace(): Promise<void> {
  const client = requiredClient();
  const { data: profile } = await client.from("profiles").select("*").eq("id", state.user!.id).maybeSingle();
  const { data: admin } = await client.from("app_admins").select("user_id").eq("user_id", state.user!.id).maybeSingle();
  state.profile = profile;
  state.isAdmin = Boolean(admin);
  const { data: memberships, error: memberError } = await client.from("organisation_members").select("organisation_id,role,organisations(id,name,slug,industry,active)").eq("user_id", state.user!.id);
  if (memberError) throw memberError;
  let organisations: Organisation[] = (memberships || []).map((row: Row) => row.organisations).filter(Boolean);
  if (state.isAdmin) {
    const { data, error } = await client.from("organisations").select("id,name,slug,industry,active").is("archived_at", null).order("name");
    if (error) throw error;
    organisations = data || [];
  }
  state.organisations = organisations;
  const stored = localStorage.getItem("mase-active-org");
  state.activeOrganisation = organisations.find(org => org.id === stored) || organisations[0] || null;
  const membership = (memberships || []).find((row: Row) => row.organisation_id === state.activeOrganisation?.id);
  state.role = state.isAdmin ? "admin" : ((membership?.role || "client") as WorkspaceRole);
  const { count } = await client.from("notifications").select("id", { count: "exact", head: true }).eq("user_id", state.user!.id).is("read_at", null);
  state.unreadNotifications = count || 0;
}

function navLink([route, title]: string[], current: string): string {
  return `<a class="side-link" href="/portal/${route}/" data-route="${route}" ${current === route ? 'aria-current="page"' : ""}><span class="side-icon">${icon[route]}</span>${title}</a>`;
}

function shell(current: string, title: string, content: string): void {
  const profileName = String(state.profile?.full_name || state.user?.email || "Workspace user");
  const orgSelect = state.organisations.length ? `<div class="org-switch"><label for="org-switch">Client workspace</label><select id="org-switch">${state.organisations.map(org => `<option value="${org.id}" ${org.id === state.activeOrganisation?.id ? "selected" : ""}>${e(org.name)}</option>`).join("")}</select></div>` : "";
  app.innerHTML = `<div class="workspace"><aside class="sidebar" id="workspace-sidebar"><div class="sidebar-head"><a href="/" aria-label="Mase the Creative website"><img class="workspace-logo" src="/brand/mase-logo.png" alt="Mase the Creative"></a><button class="icon-button sidebar-close" data-menu-close aria-label="Close menu">×</button></div>${orgSelect}<nav class="side-nav" aria-label="Workspace">${clientNav.map(item => navLink(item,current)).join("")}${state.isAdmin ? `<span class="side-nav-group">Admin</span>${adminNav.map(item => navLink(item,current)).join("")}` : `<span class="side-nav-group">Support</span>${navLink(["requests","Requests"],current)}`}</nav><div class="sidebar-foot"><div class="user-chip"><span class="avatar">${e(initials(profileName))}</span><div><strong>${e(profileName)}</strong><span>${e(label(state.role))}</span></div></div></div></aside><div class="workspace-body"><header class="topbar"><div class="topbar-left"><button class="icon-button menu-toggle" data-menu-open aria-label="Open menu">☰</button><h1>${e(title)}</h1><span class="topbar-org">${e(state.activeOrganisation?.name || "No client selected")}</span></div><div class="topbar-actions">${state.activeOrganisation ? `<button class="button small" data-quick-idea>+ New idea</button>` : ""}<button class="icon-button notification-button" data-notifications aria-label="Notifications${state.unreadNotifications ? `, ${state.unreadNotifications} unread` : ""}">♢${state.unreadNotifications ? `<span>${state.unreadNotifications}</span>` : ""}</button><button class="button small ghost" data-sign-out>Sign out</button></div></header><main class="content" id="workspace-main">${content}</main></div></div>`;
  app.querySelectorAll<HTMLAnchorElement>("[data-route]").forEach(link => link.addEventListener("click", event => { event.preventDefault(); go(`${link.dataset.route}/`); }));
  app.querySelector<HTMLElement>("[data-menu-open]")?.addEventListener("click", () => app.querySelector(".sidebar")?.classList.add("open"));
  app.querySelector<HTMLElement>("[data-menu-close]")?.addEventListener("click", () => app.querySelector(".sidebar")?.classList.remove("open"));
  app.querySelector<HTMLElement>("[data-sign-out]")?.addEventListener("click", async () => { await requiredClient().auth.signOut(); });
  app.querySelector<HTMLElement>("[data-notifications]")?.addEventListener("click", openNotifications);
  app.querySelector<HTMLElement>("[data-quick-idea]")?.addEventListener("click", openIdeaForm);
  app.querySelector<HTMLSelectElement>("#org-switch")?.addEventListener("change", async event => {
    const id = (event.currentTarget as HTMLSelectElement).value;
    state.activeOrganisation = state.organisations.find(org => org.id === id) || null;
    localStorage.setItem("mase-active-org", id);
    await loadWorkspace();
    await renderRoute();
  });
}

async function openNotifications(): Promise<void> {
  const client = requiredClient();
  const { data, error } = await client.from("notifications").select("*").eq("user_id", state.user!.id).order("created_at", { ascending: false }).limit(30);
  if (error) return toast(error.message, "error");
  const rows = data || [];
  const modal = dialog("Notifications", "Workspace activity", rows.length ? `<div class="list">${rows.map((row:Row)=>`<article class="list-item"><div><h4>${e(row.title)}</h4><p>${e(row.body)}</p><small>${fmtDate(row.created_at,true)}</small></div>${row.href?`<a class="button small" href="${e(row.href)}">Open</a>`:""}</article>`).join("")}</div><button class="button small" data-mark-read>Mark all as read</button>` : `<div class="empty"><div><strong>You are up to date.</strong>New comments, approvals and requests can appear here.</div></div>`);
  modal.querySelector<HTMLElement>("[data-mark-read]")?.addEventListener("click", async () => {
    const { error } = await client.from("notifications").update({ read_at: new Date().toISOString() }).eq("user_id", state.user!.id).is("read_at", null);
    if (error) toast(error.message,"error"); else { state.unreadNotifications=0; closeDialog(); await renderRoute(); }
  });
}

function heading(eyebrow: string, title: string, text: string, actions = ""): string {
  return `<header class="page-heading"><div><span class="eyebrow">${e(eyebrow)}</span><h2>${e(title)}</h2><p>${e(text)}</p></div>${actions ? `<div class="page-actions">${actions}</div>` : ""}</header>`;
}

function noOrganisation(): void {
  shell("overview", "Workspace", `${heading("No client linked", "Your workspace is nearly ready", "An administrator needs to link this account to a client organisation.")}<div class="empty"><div><strong>No organisation is available yet.</strong>Contact Mase the Creative if you believe this is a mistake.</div></div>`);
}

async function overviewPage(): Promise<void> {
  const client = requiredClient();
  const org = state.activeOrganisation!;
  const [ideasResult, contentResult, sessionsResult, requestsResult,analyticsResult] = await Promise.all([
    client.from("ideas").select("id,title,status,priority,target_date,updated_at").eq("organisation_id",org.id).is("archived_at",null).order("updated_at",{ascending:false}),
    client.from("content_items").select("id,title,approval_status,caption_approval_status,final_approval_status,scheduled_at,published_url,updated_at").eq("organisation_id",org.id).is("archived_at",null).order("updated_at",{ascending:false}),
    client.from("filming_sessions").select("id,title,starts_at,location,completed_at").eq("organisation_id",org.id).gte("starts_at",new Date(Date.now()-86400000).toISOString()).order("starts_at").limit(5),
    client.from("client_requests").select("id,title,status,priority,updated_at").eq("organisation_id",org.id).is("archived_at",null).order("updated_at",{ascending:false}).limit(5),
    client.from("analytics_periods").select("*").eq("organisation_id",org.id).order("period_end",{ascending:false}).limit(1).maybeSingle(),
  ]);
  const error = [ideasResult,contentResult,sessionsResult,requestsResult,analyticsResult].find(result => result.error)?.error;
  if (error) throw error;
  const ideas = ideasResult.data || [], content = contentResult.data || [], sessions = sessionsResult.data || [], requests = requestsResult.data || [],analytics=analyticsResult.data;
  const activeIdeas = ideas.filter(x => !["published","archived"].includes(x.status));
  const awaiting = content.filter(x => x.caption_approval_status === "awaiting_approval" || x.final_approval_status === "awaiting_approval");
  const scheduled: Row[] = [...content.filter(x => x.scheduled_at), ...sessions].sort((a: Row,b: Row) => new Date(a.scheduled_at || a.starts_at).getTime()-new Date(b.scheduled_at || b.starts_at).getTime()).slice(0,5);
  const monthStart=new Date();monthStart.setDate(1);monthStart.setHours(0,0,0,0);const monthEnd=new Date(monthStart.getFullYear(),monthStart.getMonth()+1,1);
  const scheduledThisMonth=content.filter(x=>x.scheduled_at&&new Date(x.scheduled_at)>=monthStart&&new Date(x.scheduled_at)<monthEnd);
  const counts={submitted:ideas.length,approved:ideas.filter(x=>["approved","ready_to_film","filmed","editing","awaiting_approval","scheduled","published"].includes(x.status)).length,filmed:ideas.filter(x=>["filmed","editing","awaiting_approval","scheduled","published"].includes(x.status)).length,scheduled:ideas.filter(x=>["scheduled","published"].includes(x.status)).length,published:ideas.filter(x=>x.status==="published").length};
  const body = `${heading("Client workspace", `Good ${new Date().getHours()<12?"morning":new Date().getHours()<18?"afternoon":"evening"}`, "Here is what is moving, what needs a decision and what is coming next.", `<button class="button primary" data-page-new-idea>+ Add an idea</button>`)}
    <section class="metric-grid"><article class="metric"><span>Awaiting discussion</span><strong>${ideas.filter(x=>["new_idea","discussing"].includes(x.status)).length}</strong><small>Ideas to shape</small></article><article class="metric"><span>Ready to film</span><strong>${ideas.filter(x=>x.status==="ready_to_film").length}</strong><small>${sessions[0]?`Next: ${fmtDate(sessions[0].starts_at)}`:"No date planned"}</small></article><article class="metric"><span>In editing</span><strong>${ideas.filter(x=>x.status==="editing").length}</strong><small>Production in progress</small></article><article class="metric"><span>Awaiting approval</span><strong>${awaiting.length}</strong><small>Caption or final content</small></article></section>
    <section class="panel pipeline-progress"><div class="panel-head"><h3>Content progress</h3><span>${scheduledThisMonth.length} scheduled this month</span></div><div class="progress-steps">${Object.entries(counts).map(([name,value])=>`<div><strong>${value}</strong><span>${label(name)}</span></div>`).join("")}</div></section>
    <div class="dashboard-grid"><section class="panel"><div class="panel-head"><h3>Content moving now</h3><a href="/portal/ideas/" data-route-link="ideas">View pipeline</a></div>${activeIdeas.length?`<div class="list">${activeIdeas.slice(0,6).map(row=>`<article class="list-item"><button data-open-idea="${row.id}"><h4>${e(row.title)}</h4><p>Updated ${fmtDate(row.updated_at)}</p></button><span class="pill ${row.status}">${e(label(row.status))}</span></article>`).join("")}</div>`:`<div class="empty"><div><strong>No active ideas yet.</strong>Add the first useful idea for this client.</div></div>`}</section>
    <aside class="panel"><div class="panel-head"><h3>Next up</h3><a href="/portal/calendar/" data-route-link="calendar">Calendar</a></div>${scheduled.length?`<div class="list">${scheduled.map(row=>`<article class="list-item"><div><h4>${e(row.title)}</h4><p>${fmtDate(row.scheduled_at||row.starts_at,true)}</p></div><span class="pill ${row.approval_status||"ready_to_film"}">${row.scheduled_at?"Post":"Filming"}</span></article>`).join("")}</div>`:`<div class="empty"><div><strong>Nothing scheduled.</strong>Upcoming shoots and posts will appear here.</div></div>`}</aside></div>
    <section class="panel" style="margin-top:.9rem"><div class="panel-head"><h3>Monthly performance summary</h3><a href="/portal/performance/" data-route-link="performance">View performance</a></div>${analytics?`<p>${e(analytics.summary||"The latest report is ready, with detailed recommendations in Performance.")}</p><div class="form-row"><div><span class="eyebrow">What worked</span><p>${e(analytics.wins||"Not recorded yet.")}</p></div><div><span class="eyebrow">What we should do next</span><p>${e(analytics.opportunities||"Not recorded yet.")}</p></div></div>`:`<div class="empty"><div><strong>No monthly summary yet.</strong>Mase will add a plain-English performance review here.</div></div>`}</section>`;
  shell("overview","Overview",body);
  app.querySelector<HTMLElement>("[data-page-new-idea]")?.addEventListener("click",openIdeaForm);
  wireLinksAndIdeas();
}

function wireLinksAndIdeas(): void {
  app.querySelectorAll<HTMLElement>("[data-route-link]").forEach(link => link.addEventListener("click", event => { event.preventDefault(); go(`${link.dataset.routeLink}/`); }));
  app.querySelectorAll<HTMLElement>("[data-open-idea]").forEach(button => button.addEventListener("click", () => openIdeaDetail(button.dataset.openIdea!)));
}

async function uploadWorkspaceFile(file:File,category:string,visibility="client"):Promise<Row>{
  const client=requiredClient(),org=state.activeOrganisation!;
  if(file.size>100*1024*1024)throw new Error("Files must be 100 MB or smaller.");
  const clean=file.name.replace(/[^a-zA-Z0-9._-]/g,"-");const path=`${org.id}/${crypto.randomUUID()}-${clean}`;
  const {data:record,error:recordError}=await client.from("workspace_files").insert({organisation_id:org.id,storage_path:path,file_name:file.name,mime_type:file.type,size_bytes:file.size,category,visibility}).select("*").single();
  if(recordError)throw recordError;
  const {error:uploadError}=await client.storage.from("workspace").upload(path,file,{upsert:false});
  if(uploadError){await client.from("workspace_files").delete().eq("id",record.id);throw uploadError;}
  return record;
}

